	function loadLottieAnimation(containerId, path, loop, autoplay) {
		let animation = lottie.loadAnimation({
			container: document.getElementById(containerId),
			renderer: "svg",
			loop: loop,
			autoplay: autoplay,
			path: path,
		});
		return animation;
	}
	
