	let katanaParts2 = loadLottieAnimation("katana-parts-animation__item--2", "./js/lottie-animations/white-part-2.json", false, false);
	let katanaParts3 = loadLottieAnimation("katana-parts-animation__item--3", "./js/lottie-animations/white-part-3.json", false, false);
