	// function for animation katana-step wrapper (content with numbers)
	function animateKatanaStepWrapper(step, direction) {
		gsap.timeline().fromTo(
			`.katana-step--${step} .katana-step__wrapper`,
			{ y: remToPx(direction === 'in' ? 2 : 0) },
			{
				y: remToPx(direction === 'in' ? 0 : -2),
				opacity: direction === 'in' ? 1 : 0,
				duration: 0.6,
				ease: 'power1.inOut',
			}
		);
	}

	// function for changing active class for neon
	function toggleActiveNeonClass(neonClass) {
		$('.samurai-katana__neon').removeClass('active');
		$(`.samurai-katana__neon--${neonClass}`).addClass('active');
	}

	// function for handle steps katana
	function handleKatanaStep(step, neonClass, katanaPart, start, end, onEnterActions = () => {}, onLeaveActions = () => {}) {
		gsap.timeline({
			scrollTrigger: {
				trigger: ".hero",
				start: start,
				end: end,
				// markers: true,
				onEnter: () => {
					toggleActiveNeonClass(neonClass);
					onEnterActions();
					animateKatanaStepWrapper(step, 'in');
					setTimeout(() => { katanaPart.play() }, 500);
				},
				onLeave: () => {
					onLeaveActions();
					toggleActiveNeonClass('');
					setTimeout(() => resetAllNumbers(document.querySelector(`.katana-step--${step}`)), 500);
					animateKatanaStepWrapper(step, 'out');
				},
				onEnterBack: () => {
					toggleActiveNeonClass(neonClass);
					onEnterActions();
					animateKatanaStepWrapper(step, 'in');
					setTimeout(() => { katanaPart.play() }, 500);
				},
				onLeaveBack: () => {
					onLeaveActions();
					toggleActiveNeonClass('');
					animateKatanaStepWrapper(step, 'out');
				},
			}
		});
	}

