	const words = ["codex", "bushido"];
	let index = 0;
	const textElement = document.querySelector(".change-word");

	function typeWord(word, callback) {
		let charIndex = 0;
		const interval = setInterval(() => {
			textElement.textContent = word.slice(0, charIndex + 1);
			charIndex++;
			if (charIndex === word.length) {
				clearInterval(interval);
				setTimeout(callback, 2000); // Пауза перед видаленням
			}
		}, 200); // Швидкість друку символів
	}

	function deleteWord(callback) {
		let charIndex = textElement.textContent.length;
		const interval = setInterval(() => {
			textElement.textContent = textElement.textContent.slice(0, charIndex - 1);
			charIndex--;
			if (charIndex === 0) {
				clearInterval(interval);
				setTimeout(callback, 500); // Пауза перед друком нового слова
			}
		}, 100); // Швидкість стирання символів
	}

	function cycleWords() {
		deleteWord(() => {
			index = (index + 1) % words.length;
			typeWord(words[index], cycleWords);
		});
	}

	typeWord(words[index], cycleWords);




